<?php
namespace App\Http\Controllers\Admin;use App\Http\Controllers\Controller;use App\Models\Game;use App\Models\GamePackage;use App\Models\Provider;use Illuminate\Http\Request;use Illuminate\Support\Str;class PackageController extends Controller{public function index(){$packages=GamePackage::with('game','provider')->latest()->paginate(20);return view('admin.packages.index',compact('packages'));}public function create(){return view('admin.packages.form',['package'=>new GamePackage,'games'=>Game::where('is_active',1)->get(),'providers'=>Provider::where('status','active')->get()]);}public function store(Request $r){GamePackage::create($this->data($r));return redirect()->route('admin.packages.index')->with('success','Package saved.');}public function edit(GamePackage $package){return view('admin.packages.form',['package'=>$package,'games'=>Game::where('is_active',1)->get(),'providers'=>Provider::where('status','active')->get()]);}public function update(Request $r,GamePackage $package){$package->update($this->data($r));return redirect()->route('admin.packages.index')->with('success','Package updated.');}private function data(Request $r){$d=$r->validate(['game_id'=>'required|exists:games,id','provider_id'=>'required|exists:providers,id','name'=>'required|max:191','sku'=>'nullable|max:191','price'=>'required|numeric|min:1','currency_code'=>'required|max:3','credit_label'=>'required|max:191','provider_product_id'=>'required|max:191','delivery_mode'=>'required|max:50','image'=>'nullable|max:191','sort_order'=>'nullable|integer']);$d['price_minor']=(int)round($d['price']*100);unset($d['price']);$d['is_active']=$r->boolean('is_active');$d['sku']=$d['sku']?:strtoupper(Str::slug($d['name'],'_'));return $d;}}
